1	// Embeddings.
2	//
3	// Spec uses vector(1536) — the OpenAI text-embedding-3-small dimension.
4	// OpenRouter doesn't host that exact model, so:
5	//
6	//   1. If OPENAI_API_KEY is set, call OpenAI directly for text-embedding-3-small.
7	//   2. Otherwise, return a deterministic-zero vector (length 1536) so the rest
8	//      of the system can be exercised without breaking the column type.
9	//
10	// See DECISIONS.md D3.embeddings — do NOT silently swap the vector dimension.
11	
12	import { EMBEDDING_DIM } from '@oracle/shared';
13	
14	const OPENAI_EMBEDDING_URL = 'https://api.openai.com/v1/embeddings';
15	const MODEL = 'text-embedding-3-small';
16	
17	type EmbeddingResponse = {
18	  data: Array<{ embedding: number[] }>;
19	};
20	
21	/**
22	 * Embed a single string. Returns a vector of length EMBEDDING_DIM.
23	 * Falls back to a zero vector if OPENAI_API_KEY isn't set.
24	 */
25	export async function embedText(text: string): Promise<{
26	  vector: number[];
27	  model: string;
28	  fallback: boolean;
29	}> {
30	  const apiKey = process.env.OPENAI_API_KEY;
31	  if (!apiKey) {
32	    return { vector: new Array(EMBEDDING_DIM).fill(0), model: 'zero-stub', fallback: true };
33	  }
34	
35	  const res = await fetch(OPENAI_EMBEDDING_URL, {
36	    method: 'POST',
37	    headers: {
38	      'Content-Type': 'application/json',
39	      Authorization: `Bearer ${apiKey}`,
40	    },
41	    body: JSON.stringify({ model: MODEL, input: text }),
42	  });
43	
44	  if (!res.ok) {
45	    throw new Error(`OpenAI embeddings call failed: ${res.status} ${await res.text()}`);
46	  }
47	  const body = (await res.json()) as EmbeddingResponse;
48	  const vector = body.data[0]?.embedding;
49	  if (!vector || vector.length !== EMBEDDING_DIM) {
50	    throw new Error(
51	      `OpenAI returned unexpected embedding length: ${vector?.length}. ` +
52	        `Spec locks vector(${EMBEDDING_DIM}).`,
53	    );
54	  }
55	  return { vector, model: MODEL, fallback: false };
56	}
57	
58	export async function embedMany(texts: string[]): Promise<{
59	  vectors: number[][];
60	  model: string;
61	  fallback: boolean;
62	}> {
63	  const apiKey = process.env.OPENAI_API_KEY;
64	  if (!apiKey) {
65	    return {
66	      vectors: texts.map(() => new Array(EMBEDDING_DIM).fill(0)),
67	      model: 'zero-stub',
68	      fallback: true,
69	    };
70	  }
71	  const res = await fetch(OPENAI_EMBEDDING_URL, {
72	    method: 'POST',
73	    headers: {
74	      'Content-Type': 'application/json',
75	      Authorization: `Bearer ${apiKey}`,
76	    },
77	    body: JSON.stringify({ model: MODEL, input: texts }),
78	  });
79	  if (!res.ok) {
80	    throw new Error(`OpenAI embeddings call failed: ${res.status} ${await res.text()}`);
81	  }
