1	// Alibaba Qwen model list source.
2	// Calls Alibaba DashScope's OpenAI-compatible /models endpoint and tags each
3	// row as a qwen-provider model. Pricing/caps come from OpenRouter enrichment
4	// (OpenRouter indexes Qwen models under the "qwen/" slug, which matches).
5	//
6	// Auth: DASHSCOPE_API_KEY from DashScope International console.
7	// Base URL: https://dashscope-us.aliyuncs.com/compatible-mode/v1
8	
9	import OpenAI from 'openai';
10	import type { RawProviderModel } from './types';
11	
12	const DASHSCOPE_BASE_URL = 'https://dashscope-us.aliyuncs.com/compatible-mode/v1';
13	
14	// DashScope returns the full catalog including non-chat models (text-embedding,
15	// multimodal embedding, etc.). Filter to qwen* chat/VL models.
16	const QWEN_CHAT_PREFIXES = ['qwen', 'qwq'];
17	
18	function isQwenChatModel(id: string): boolean {
19	  const lower = id.toLowerCase();
20	  return (
21	    QWEN_CHAT_PREFIXES.some((p) => lower.startsWith(p)) &&
22	    !lower.includes('embedding') &&
23	    !lower.includes('rerank') &&
24	    !lower.includes('-tts') &&
25	    !lower.includes('-asr')
26	  );
