  const value = raw.slice(sep + 1);
  if (!value) return null;
  if (kind === 'employee') return { kind, employeeId: value };
  if (kind === 'department') return { kind, department: value };
  if (kind === 'locale') return { kind, locale: value };
  return null;
}

