      .notNull(),
    replacementClaimId: uuid('replacement_claim_id').references(() => claims.id, {
      onDelete: 'set null',
    }),
    action: varchar('action', { length: 50 }).notNull(),
    reviewedByEmployeeId: uuid('reviewed_by_employee_id')
